/**
 * Get shuffled questions for a chapter
 * @param {string} slug - chapter slug
 * @param {number} count - how many questions to return
 * @param {string[]} seen - question texts already seen by user
 * @returns {Array} shuffled questions
 */
export function getQuestions(slug, count = 20, seen = []) {
  const all = QUESTIONS[slug]
  if (!all) return []

  // Filter out seen questions
  const unseen = seen.length > 0
    ? all.filter(q => !seen.includes(q.question))
    : all

  // If not enough unseen, use all (reset cycle)
  const pool = unseen.length >= count ? unseen : all

  // Fisher-Yates shuffle
  const shuffled = [...pool]
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]]
  }

  return shuffled.slice(0, count).map((q, i) => ({ ...q, id: i + 1 }))
}

export default QUESTIONS
